function StructActivityEntry:StructActivityEntry()
    self.pageId = 0             --分页id
    self.entryId = 0            --条目id
    self.title = ""             --条目标题
    self.desc = ""              --条目描述
    self.icon = ""              --条目图标
    self.items = {}             --奖励列表
    self.moreInfo=""            --json格式条目额外数据
    self.goalData=nil           --GoalPage时读取
    self.MarketData=nil         --MarketPage 时读取
