end
function StructActivityEntry:CreateByPb(pb,pageId)
    self.pageId = pageId
    self.entryId = pb.entryId
    self.title = pb.title
    self.desc = pb.desc
    self.icon = pb.icon
    self.items={}
    for i, v in ipairs(pb.items) do
        local item = StructRewardItem:New()
        item:CreateByPb(v)
        table.insert(self.items,item)
    end
    self.moreInfo = pb.moreInfo
    if(pb.goalData)then
        self.goalData =StructGoalData:New()
        self.goalData:CreateByPb(pb.goalData)
    end
    if(pb.MarketData)then
        self.MarketData =StructMarketData:New()
        self.MarketData:CreateByPb(pb.MarketData)
    end
    self.sort = pb.sort
end
return StructActivityEntry